object.script:
--gs = grow state --ls = light state --t = time pattern1= { {gs=false,ls=false,t= 1},{gs= true,ls=false,t=80},{gs=false,ls=false,t= 5},{gs= true,ls=false,t= 5}, {gs=false,ls=false,t= 1},{gs=false,ls= true,t=100} }
pattern2= { {gs=false,ls=false,t= 1},{gs= true,ls=false,t=120},{gs=false,ls=false,t= 20},{gs=false,ls= true,t= 3}, {gs=false,ls=false,t= 25},{gs= true,ls=false,t= 15},{gs=false,ls=false,t= 10},{gs= true,ls=false,t= 10}, {gs=false,ls=false,t= 15},{gs= true,ls=false,t= 3},{gs=false,ls=false,t= 5},{gs=false,ls= true,t= 2}, {gs=false,ls=false,t= 3},{gs= true,ls=false,t= 4},{gs=false,ls= true,t= 2},{gs=false,ls=false,t= 5}, {gs=false,ls= true,t=100},{gs= true,ls=false,t=150},{gs=false,ls= true,t= 1},{gs=false,ls=false,t= 3}, {gs= true,ls=false,t= 1},{gs=false,ls=false,t= 1},{gs=false,ls= true,t=100} }
pattern3= { {gs=false,ls=false,t= 1},{gs= true,ls=false,t=120},{gs=false,ls=false,t= 20},{gs=false,ls= true,t= 3}, {gs=false,ls=false,t= 15},{gs= true,ls=false,t= 10},{gs=false,ls=false,t= 10},{gs=false,ls= true,t= 10}, {gs=false,ls=false,t= 5},{gs= true,ls=false,t= 20},{gs=false,ls=false,t= 5},{gs= true,ls=false,t= 15}, {gs=false,ls= true,t=100} } patterns={pattern1,pattern2,pattern3}
time=0 grow=false light=false first=true function onTick() if first then first=false pattern = patterns[(property.getNumber("Lighting pattern"))]
alltime=0 for i , v in ipairs(pattern) do alltime = alltime + v.t end end
if input.getBool(1) then if time < alltime then time = time + 1 end else time = 0 end
tick=0 for i , v in ipairs(pattern) do if tick <= time then grow = v.gs light = v.ls end tick = tick + v.t end R=0 G=0 B=0 if grow then R = 0.01 B = 0.1 end if light then R = 1 G = 1 B = 1 end output.setNumber(1,R) output.setNumber(2,G) output.setNumber(3,B) output.setBool(1,light) end

